SELECT
    id, parent_id, subject_id, title, description, child_age, class_mode, city, address,
    budget_min, budget_max, stage_code, education_requirement, schedule, status, create_time, update_time
FROM student_job_posting
WHERE status = 1

    AND subject_id = #{subjectId}


    AND class_mode = #{classMode}


    AND city = #{city}


    AND stage_code = #{stageCode}


    AND education_requirement = #{educationRequirement}


    AND (budget_max IS NULL OR budget_max >= #{budgetMin})


    AND (budget_min IS NULL OR budget_min <= #{budgetMax})


    AND (title LIKE CONCAT('%', #{keyword}, '%') OR description LIKE CONCAT('%', #{keyword}, '%'))


    AND id < #{cursor}



